export function mergeChordsExpansion2(target, expansion) {
    for (const key of Object.keys(expansion)) {
        if (target[key]) {
            target[key] = target[key].concat(expansion[key]);
        } else {
            target[key] = [...expansion[key]];
        }
    }
}
